<?php
namespace App\Http\Controllers\Api\Admin\Marketing;
use App\Http\Controllers\Concerns\ApiResponses; use App\Http\Controllers\Controller; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\DB;
class SettingsAdminController extends Controller { use ApiResponses; public function marketing(): JsonResponse { return $this->success(DB::table('marketing_settings')->get()); } public function updateMarketing(Request $r): JsonResponse { $d=$r->validate(['settings'=>'required|array']); foreach($d['settings'] as $k=>$v) DB::table('marketing_settings')->updateOrInsert(['key'=>$k],['value'=>json_encode($v),'group'=>'marketing','updated_at'=>now(),'created_at'=>now()]); return $this->success(['message'=>'Marketing settings updated.']); } public function analytics(): JsonResponse { return $this->success(DB::table('analytics_settings')->get()); } public function updateAnalytics(Request $r): JsonResponse { $d=$r->validate(['settings'=>'required|array']); foreach($d['settings'] as $k=>$v) DB::table('analytics_settings')->updateOrInsert(['key'=>$k],['value'=>json_encode($v),'group'=>'analytics','updated_at'=>now(),'created_at'=>now()]); return $this->success(['message'=>'Analytics settings updated.']); } }
